// ===========================================================================
// nuliga-sync — n8n Code node
//
// Setup:
//   1. Set n8n env var: NODE_FUNCTION_ALLOW_EXTERNAL=cheerio,js-yaml
//   2. Paste the contents of `tools/nuliga-sync/dist/n8n-bundle.js` BELOW the
//      `--- PASTE BUNDLE BELOW ---` marker (replace this placeholder)
//   3. Set n8n env vars: GITHUB_TOKEN, GITHUB_OWNER (ElGarno), GITHUB_REPO (tcbw-homepage)
//
// This node runs the full sync and returns an object with either:
//   { changed: false }    → workflow ends
//   { changed: true, prUrl, prTitle, prBody, missingCount, updateCount, addCount }
// ===========================================================================

const cheerio = require('cheerio');
const yaml = require('js-yaml');

// --- PASTE BUNDLE BELOW ---
// ... entire content of tools/nuliga-sync/dist/n8n-bundle.js goes here ...
// --- PASTE BUNDLE ABOVE ---

const GITHUB_TOKEN = $env.GITHUB_TOKEN;
const OWNER = $env.GITHUB_OWNER;
const REPO = $env.GITHUB_REPO;
const API = `https://api.github.com/repos/${OWNER}/${REPO}`;

async function gh(path, opts = {}) {
  const res = await fetch(`${API}${path}`, {
    ...opts,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'nuliga-sync',
      ...(opts.headers ?? {}),
    },
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`GitHub API ${path} ${res.status}: ${body.slice(0, 300)}`);
  }
  return res.json();
}

async function readRepoFile(path) {
  const data = await gh(`/contents/${encodeURI(path)}?ref=main`);
  return Buffer.from(data.content, 'base64').toString('utf8');
}

async function findOpenSyncPR() {
  const pulls = await gh(`/pulls?state=open&per_page=50`);
  return pulls.find(p => p.head.ref.startsWith('nuliga-sync/'));
}

async function commitAndOpenPR({ branch, commitMessage, prTitle, prBody, fileChanges }) {
  const mainRef = await gh('/git/ref/heads/main');
  const baseSha = mainRef.object.sha;

  await gh('/git/refs', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ ref: `refs/heads/${branch}`, sha: baseSha }),
  });

  const baseCommit = await gh(`/git/commits/${baseSha}`);
  const baseTree = baseCommit.tree.sha;

  const treeEntries = fileChanges.map(f => ({
    path: f.path,
    mode: '100644',
    type: 'blob',
    content: f.content,
  }));

  const tree = await gh('/git/trees', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ base_tree: baseTree, tree: treeEntries }),
  });

  const commit = await gh('/git/commits', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: commitMessage, tree: tree.sha, parents: [baseSha] }),
  });

  await gh(`/git/refs/heads/${branch}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sha: commit.sha }),
  });

  const pr = await gh('/pulls', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      title: prTitle,
      body: prBody,
      head: branch,
      base: 'main',
      draft: true,
    }),
  });

  try {
    await gh(`/issues/${pr.number}/labels`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ labels: ['automated', 'nuliga-sync'] }),
    });
  } catch (e) {
    // labels optional — continue
  }

  return pr;
}

async function commentOnPR(prNumber, body) {
  await gh(`/issues/${prNumber}/comments`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ body }),
  });
}

const result = await runSync({
  fetchImpl: fetch,
  readRepoFile,
  today: new Date(),
});

if (!result.changed) {
  return [{ json: { changed: false, errors: result.errors } }];
}

const existingPR = await findOpenSyncPR();
if (existingPR) {
  await commentOnPR(existingPR.number, `Zusätzliche Änderungen seit PR-Erstellung:\n\n${result.prBody}`);
  return [{
    json: {
      changed: true,
      action: 'comment',
      prUrl: existingPR.html_url,
      prTitle: existingPR.title,
      prBody: result.prBody,
      errors: result.errors,
    },
  }];
}

const pr = await commitAndOpenPR(result);
return [{
  json: {
    changed: true,
    action: 'created',
    prUrl: pr.html_url,
    prNumber: pr.number,
    prTitle: result.prTitle,
    prBody: result.prBody,
    errors: result.errors,
  },
}];
